VALUES
  ('bookkeeper-moex-00212', 'bookkeeper', 'bookkeeper-moex-113-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '某候選人洽請李記帳士為其競選活動處理帳務申報事宜，但李記帳士擔心其並無類似經驗，且因時限考量， 經評估後婉拒接受委任。請問李記帳士之作為，與我國記帳士職業倫理道德規範中的那一項要求關聯性最低？', '["誠正", "務實", "保密", "適任"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1ce3c04d33b5", "answer_pdf_sha1": "68e6408d1165", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00213', 'bookkeeper', 'bookkeeper-moex-113-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '在記帳士事務所任職的助理黃君，有以下何種作為時，將被視為違反記帳士職業倫理道德規範？', '["未經客戶同意，洩漏業務上之秘密", "依指示在特定時間將客戶相關的帳務資料文件等送交主管機關", "拒絕客戶因貸款需求，協助美化財務報表之請託", "記帳士職業倫理道德規範僅適用於記帳士，黃君係助理人員，因此並無適用問題"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1ce3c04d33b5", "answer_pdf_sha1": "68e6408d1165", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00214', 'bookkeeper', 'bookkeeper-moex-113-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '關於商業記帳本位與記帳文字之規定，下列敘述何者錯誤？', '["商業因業務需要，財務報表得以新臺幣、外幣併列方式編製", "商業會計之記載，除記帳數字適用阿拉伯字外，應以我國文字為之", "商業不得以外幣編製決算報表", "商業記帳以仟元為單位，但得依交易之性質延長，改以元為單位"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1ce3c04d33b5", "answer_pdf_sha1": "68e6408d1165", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00215', 'bookkeeper', 'bookkeeper-moex-113-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '下列何者屬於對外會計事項？①倉庫失火未投保的存貨焚毀  ②銀行撥款先前申貸的款項入帳  ③繳納', '["提列折舊  ⑤發放現金股利  ⑥業主自商業提取商品自用", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1ce3c04d33b5", "answer_pdf_sha1": "68e6408d1165", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00216', 'bookkeeper', 'bookkeeper-moex-113-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '商業自辦員工午餐，部分蔬果係購自市場小販，無法取得原始憑證。下列有關帳務處理之敘述，何者正確？', '["無法證明交易之事實，不可入帳", "可根據其事實及金額作成憑證，由商業負責人或其指定人員簽章，憑以記帳", "由採購人員開立內部憑證，經市場小販簽章後，憑以記帳", "由會計人員依金額大小援例處理"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1ce3c04d33b5", "answer_pdf_sha1": "68e6408d1165", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00217', 'bookkeeper', 'bookkeeper-moex-113-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依商業會計法之規定，下列有關會計帳簿之敘述，何者錯誤？', '["商業必須設置之會計帳簿，為普通序時帳簿及總分類帳簿", "商業所置之各種會計帳簿，均應按其頁數順序編號，不得毀損", "會計制度健全，使用總分類帳會計項目日計表者，得免設總分類帳簿", "在同一會計年度內應連續記載，除已用盡外不得更換新帳簿"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1ce3c04d33b5", "answer_pdf_sha1": "68e6408d1165", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00218', 'bookkeeper', 'bookkeeper-moex-113-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依商業會計法之規定，資產之折舊方法有那些？①平均法  ②生產數量法  ③加權平均法  ④年數合計法 ⑤工作時間法', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1ce3c04d33b5", "answer_pdf_sha1": "68e6408d1165", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00219', 'bookkeeper', 'bookkeeper-moex-113-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '下列有關資產重估價之敘述，何者錯誤？', '["固定資產遇有物價指數上漲達25%以上時，可依法令辦理重估價", "供營業長期使用之自用土地，得依土地公告現值調整價值", "重估或調整之資產而發生之增值，應列為未實現重估增值", "經重估之固定資產，自重估年度起，以重估價值為基礎計提折舊"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1ce3c04d33b5", "answer_pdf_sha1": "68e6408d1165", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
